public class DataProcessor {
    public void processAccounts() {
        List<Account> accounts = [SELECT Id FROM Account WHERE IsShared = true];
        // Process the shared accounts
    }

    public void processUserContacts() {
        List<Contact> contacts = [SELECT Id FROM Contact WHERE IsShared = false];
        // Process the user's contacts
    }
}
```

