```apex
public class CurrencyConverter {
    // Map of currency codes to their corresponding Salesforce currency symbols
    private static Map<String, String> currencyMap = new Map<String, String>();

    static {
        // Initialize the currency map
        currencyMap.put('USD', '$');
        currencyMap.put('EUR', '€');
        currencyMap.put('GBP', '£');
        currencyMap.put('JPY', '¥');
        // Add more currency codes as needed
    }

    public static String convertCurrency(String amount, String currencyCode) {
        // Check if the currency code is valid
        if (!currencyMap.containsKey(currencyCode)) {
            throw new InvalidCurrencyCodeException('Invalid currency code');
        }

        // Get the currency symbol from the map
        String currencySymbol = currencyMap.get(currencyCode);

        // Format the amount with the currency symbol
        String formattedAmount = currencySymbol + amount;

        return formattedAmount;
    }
}

// Custom exception for invalid currency codes
public class InvalidCurrencyCodeException : SystemException {
    private String message;

    public InvalidCurrencyCodeException(String message) {
        this.message = message;
    }

    public String getMessage() {
        return message;
    }
}
